134→// ExecuteFunction instruments the given source file for the target function,
135→// generates a main harness that calls it with the given JSON inputs, compiles,
136→// runs, and returns the collected results.
137→// The mocks parameter provides mock configurations for external dependencies.
138→func ExecuteFunction(sourcePath, funcName string, inputs []json.RawMessage, mocks ...[]MockConfig) (*ExecuteResult, error) {
139→	// Analyze the function to get parameter types
140→	params, returnInfo, err := analyzeForExecution(sourcePath, funcName)
141→	if err != nil {
142→		return nil, fmt.Errorf("analyzing function: %w", err)
143→	}
144→
145→	if len(inputs) != len(params) {
146→		return nil, fmt.Errorf("expected %d inputs for %s, got %d", len(params), funcName, len(inputs))
147→	}
148→
149→	// Instrument the file
150→	outputDir, err := InstrumentFile(sourcePath, &funcName, nil)
151→	if err != nil {
152→		return nil, fmt.Errorf("instrumenting: %w", err)
153→	}
154→	defer os.RemoveAll(outputDir)
155→
156→	// Rewrite all Go files in the output dir to package main so the harness can call them.
157→	if err := rewritePackageToMain(outputDir); err != nil {
158→		return nil, fmt.Errorf("rewriting package: %w", err)
159→	}
160→
161→	// Generate mock support file if mocks are provided.
162→	activeMocks := flattenMocks(mocks)
163→	mocksPath := filepath.Join(outputDir, "shatter_external_calls.json")
164→	if len(activeMocks) > 0 {
165→		mockSource := generateMockFile(activeMocks, mocksPath)
166→		mockFilePath := filepath.Join(outputDir, "shatter_mocks.go")
167→		if err := os.WriteFile(mockFilePath, []byte(mockSource), 0644); err != nil {
168→			return nil, fmt.Errorf("writing shatter_mocks.go: %w", err)
169→		}
170→	}
171→
172→	// Generate the main harness
173→	resultsPath := filepath.Join(outputDir, "shatter_results.json")
174→	returnPath := filepath.Join(outputDir, "shatter_return.json")
175→	perfPath := filepath.Join(outputDir, "shatter_perf.json")
176→	harness, err := generateHarness(funcName, params, returnInfo, inputs, resultsPath, returnPath, perfPath, len(activeMocks) > 0)
177→	if err != nil {
178→		return nil, fmt.Errorf("generating harness: %w", err)
179→	}
180→
181→	mainPath := filepath.Join(outputDir, "main.go")
182→	if err := os.WriteFile(mainPath, []byte(harness), 0644); err != nil {
183→		return nil, fmt.Errorf("writing main.go: %w", err)
184→	}
185→
186→	// Build the binary
187→	binaryName := "shatter_run"
188→	if runtime.GOOS == "windows" {
189→		binaryName += ".exe"
190→	}
191→	binaryPath := filepath.Join(outputDir, binaryName)
192→
193→	buildCtx, buildCancel := context.WithTimeout(context.Background(), buildTimeout())
194→	defer buildCancel()
195→
196→	buildCmd := exec.CommandContext(buildCtx, "go", "build", "-o", binaryPath, ".")
197→	buildCmd.Dir = outputDir
198→	if buildOut, err := buildCmd.CombinedOutput(); err != nil {
199→		return nil, fmt.Errorf("build failed: %w\n%s", err, buildOut)
200→	}
201→
202→	// Run the binary with a timeout
203→	start := time.Now()
204→	execDur := execTimeout()
205→	runCtx, runCancel := context.WithTimeout(context.Background(), execDur)
206→	defer runCancel()
207→
208→	runCmd := exec.CommandContext(runCtx, binaryPath)
209→	runCmd.Dir = outputDir
210→	var stdoutBuf, stderrBuf strings.Builder
211→	runCmd.Stdout = &stdoutBuf
212→	runCmd.Stderr = &stderrBuf
213→	runErr := runCmd.Run()
214→	wallTime := time.Since(start)
215→
216→	// Parse results even if the run failed (panic may have happened after some recording)
217→	result := &ExecuteResult{
218→		BranchPath:    []BranchDecision{},
219→		LinesExecuted: []int{},
220→		SideEffects:   []SideEffect{},
221→		ScopeEvents:   []json.RawMessage{},
222→		Performance:   PerfMetrics{WallTimeMs: float64(wallTime.Milliseconds())},
223→	}
224→
225→	// Capture stdout/stderr as structured side effects.
226→	if s := strings.TrimSpace(stdoutBuf.String()); s != "" {
227→		result.SideEffects = append(result.SideEffects, SideEffect{
228→			Kind: "console_output", Level: "log", Message: s,
229→		})
230→	}
231→	if s := strings.TrimSpace(stderrBuf.String()); s != "" {
232→		result.SideEffects = append(result.SideEffects, SideEffect{
233→			Kind: "console_output", Level: "error", Message: s,
234→		})
235→	}
236→
237→	// Try to parse the shatter recording results
238→	if data, err := os.ReadFile(resultsPath); err == nil {
239→		var recorded struct {
240→			LinesExecuted []int             `json:"lines_executed"`
241→			BranchPath    []BranchDecision  `json:"branch_path"`
242→			ScopeEvents   []json.RawMessage `json:"scope_events"`
243→		}
244→		if err := json.Unmarshal(data, &recorded); err == nil {
245→			result.LinesExecuted = recorded.LinesExecuted
246→			result.BranchPath = recorded.BranchPath
247→			result.ScopeEvents = recorded.ScopeEvents
248→		}
249→	}
250→
251→	// Try to parse the return value
252→	if data, err := os.ReadFile(returnPath); err == nil {
253→		result.ReturnValue = json.RawMessage(data)
254→	}
255→
256→	// Try to parse external call records from mock execution
257→	if len(activeMocks) > 0 {
258→		if data, err := os.ReadFile(mocksPath); err == nil {
259→			var calls []ExternalCall
260→			if err := json.Unmarshal(data, &calls); err == nil {
261→				result.ExternalCalls = calls
262→			}
263→		}
264→	}
265→
266→	// Try to parse performance metrics from the harness
267→	if data, err := os.ReadFile(perfPath); err == nil {
268→		var perf struct {
269→			CPUTimeUs          int `json:"cpu_time_us"`
270→			HeapUsedBytes      int `json:"heap_used_bytes"`
271→			HeapAllocatedBytes int `json:"heap_allocated_bytes"`
272→		}
273→		if err := json.Unmarshal(data, &perf); err == nil {
274→			result.Performance.CPUTimeUs = perf.CPUTimeUs
275→			result.Performance.HeapUsedBytes = perf.HeapUsedBytes
276→			result.Performance.HeapAllocatedBytes = perf.HeapAllocatedBytes
277→		}
278→	}
279→
280→	// Handle execution errors
281→	if runErr != nil {
282→		if runCtx.Err() == context.DeadlineExceeded {
283→			cat := "infrastructure"
284→			result.ThrownError = &ErrorInfo{
285→				ErrorType:     "timeout",
286→				Message:       fmt.Sprintf("execution timed out after %s", execDur),
287→				ErrorCategory: &cat,
288→			}
289→		} else {
290→			cat := "runtime"
291→			result.ThrownError = &ErrorInfo{
292→				ErrorType:     "runtime_error",
293→				Message:       runErr.Error(),
294→				Stack:         stderrBuf.String(),
295→				ErrorCategory: &cat,
296→			}
297→		}
298→	}
299→
300→	return result, nil
301→}
302→
303→// paramInfo holds a parameter's name and Go type string for harness generation.
304→type paramInfo struct {
305→	Name   string
306→	GoType string
307→}
308→
309→// returnTypeInfo describes what the function returns.
310→type returnTypeInfo struct {
311→	Count  int      // number of return values
312→	Types  []string // Go type strings
313→	HasErr bool     // last return is error
314→}
315→
316→// analyzeForExecution parses the source file and extracts parameter types
317→// and return type for the named function.
318→func analyzeForExecution(sourcePath, funcName string) ([]paramInfo, returnTypeInfo, error) {
319→	fset := token.NewFileSet()
320→	file, err := parser.ParseFile(fset, sourcePath, nil, parser.ParseComments)
321→	if err != nil {
322→		return nil, returnTypeInfo{}, fmt.Errorf("parsing %s: %w", sourcePath, err)
323→	}
324→
325→	// Type-check for better type resolution
326→	info := &types.Info{
327→		Types: make(map[ast.Expr]types.TypeAndValue),
328→		Defs:  make(map[*ast.Ident]types.Object),
329→		Uses:  make(map[*ast.Ident]types.Object),
330→	}
331→	conf := types.Config{
332→		Importer: importer.Default(),
333→		Error:    func(error) {},
334→	}
335→	conf.Check(file.Name.Name, fset, []*ast.File{file}, info) //nolint:errcheck
336→
337→	for _, decl := range file.Decls {
338→		fn, ok := decl.(*ast.FuncDecl)
339→		if !ok || fn.Name.Name != funcName {
340→			continue
341→		}
342→
343→		pkgName := file.Name.Name
344→		params := extractParamInfo(fn, info, pkgName)
345→		retInfo := extractReturnInfo(fn, info, pkgName)
346→		return params, retInfo, nil
347→	}
348→
349→	return nil, returnTypeInfo{}, fmt.Errorf("function not found: %s", funcName)
350→}
351→
352→func extractParamInfo(fn *ast.FuncDecl, info *types.Info, pkgName string) []paramInfo {
353→	if fn.Type.Params == nil {
354→		return nil
355→	}
356→	var params []paramInfo
357→	for _, field := range fn.Type.Params.List {
358→		goType := resolveGoType(field.Type, info, pkgName)
359→		for _, name := range field.Names {
360→			params = append(params, paramInfo{Name: name.Name, GoType: goType})
361→		}
362→	}
363→	return params
364→}
365→
366→func extractReturnInfo(fn *ast.FuncDecl, info *types.Info, pkgName string) returnTypeInfo {
367→	results := fn.Type.Results
368→	if results == nil || len(results.List) == 0 {
369→		return returnTypeInfo{}
370→	}
371→
372→	var retTypes []string
373→	for _, field := range results.List {
374→		goType := resolveGoType(field.Type, info, pkgName)
375→		if len(field.Names) == 0 {
376→			retTypes = append(retTypes, goType)
377→		} else {
378→			for range field.Names {
379→				retTypes = append(retTypes, goType)
380→			}
381→		}
382→	}
383→
384→	hasErr := len(retTypes) > 0 && retTypes[len(retTypes)-1] == "error"
385→	return returnTypeInfo{
386→		Count:  len(retTypes),
387→		Types:  retTypes,
388→		HasErr: hasErr,
389→	}
390→}
391→
392→// resolveGoType returns the Go type string for a type expression.
393→// The pkgName parameter is the source file's package name; types qualified
394→// with this prefix (e.g. "examples.User") are stripped to the bare name
395→// because the instrumented code is rewritten to package main.
396→func resolveGoType(expr ast.Expr, info *types.Info, pkgName string) string {
397→	if tv, ok := info.Types[expr]; ok {
398→		s := tv.Type.String()
399→		return stripLocalPkg(s, pkgName)
400→	}
401→	// Fallback to AST-based type string
402→	return astTypeString(expr)
403→}
404→
405→// stripLocalPkg removes occurrences of "pkgName." from a type string so that
406→// types defined in the same package work after rewriting to package main.
407→func stripLocalPkg(typeStr, pkgName string) string {
408→	if pkgName == "" {
409→		return typeStr
410→	}
411→	return strings.ReplaceAll(typeStr, pkgName+".", "")
412→}
413→
414→func astTypeString(expr ast.Expr) string {
415→	switch e := expr.(type) {
416→	case *ast.Ident:
417→		return e.Name
418→	case *ast.ArrayType:
419→		if e.Len == nil {
420→			return "[]" + astTypeString(e.Elt)
421→		}
422→		return "[" + astTypeString(e.Len) + "]" + astTypeString(e.Elt)
423→	case *ast.StarExpr:
424→		return "*" + astTypeString(e.X)
425→	case *ast.MapType:
426→		return "map[" + astTypeString(e.Key) + "]" + astTypeString(e.Value)
427→	case *ast.SelectorExpr:
428→		return astTypeString(e.X) + "." + e.Sel.Name
429→	case *ast.InterfaceType:
430→		return "interface{}"
431→	case *ast.BasicLit:
432→		return e.Value
433→	default:
434→		return "interface{}"
435→	}
436→}
