438→// generateHarness creates a main.go that deserializes inputs, calls the function,
439→// captures results, and writes output files.
440→func generateHarness(funcName string, params []paramInfo, retInfo returnTypeInfo, inputs []json.RawMessage, resultsPath, returnPath, perfPath string, hasMocks bool) (string, error) {
441→	var b strings.Builder
442→
443→	b.WriteString("package main\n\n")
444→	b.WriteString("import (\n")
445→	b.WriteString("\t\"encoding/json\"\n")
446→	b.WriteString("\t\"fmt\"\n")
447→	b.WriteString("\t\"os\"\n")
448→	b.WriteString("\t\"runtime\"\n")
449→	b.WriteString("\t\"time\"\n")
450→	b.WriteString(")\n\n")
451→
452→	b.WriteString("func main() {\n")
453→
454→	// If mocks are active, defer dumping external call records
455→	if hasMocks {
456→		b.WriteString("\tdefer shatterDumpMockCalls()\n\n")
457→	}
458→	b.WriteString("\tvar memBefore runtime.MemStats\n")
459→	b.WriteString("\truntime.ReadMemStats(&memBefore)\n")
460→	b.WriteString("\tcpuStart := time.Now()\n\n")
461→
462→	// Declare and deserialize each input parameter
463→	for i, p := range params {
464→		inputJSON, err := json.Marshal(string(inputs[i]))
465→		if err != nil {
466→			return "", fmt.Errorf("marshaling input %d: %w", i, err)
467→		}
468→
469→		// Write the raw JSON as a string literal, then unmarshal into the typed var
470→		b.WriteString(fmt.Sprintf("\tvar %s %s\n", p.Name, p.GoType))
471→		b.WriteString(fmt.Sprintf("\tif err := json.Unmarshal([]byte(%s), &%s); err != nil {\n", inputJSON, p.Name))
472→		b.WriteString(fmt.Sprintf("\t\tfmt.Fprintf(os.Stderr, \"failed to unmarshal input %s: %%v\\n\", err)\n", p.Name))
473→		b.WriteString("\t\tos.Exit(1)\n")
474→		b.WriteString("\t}\n")
475→	}
476→
477→	b.WriteString("\n")
478→
479→	// Call the function
480→	argList := make([]string, len(params))
481→	for i, p := range params {
482→		argList[i] = p.Name
483→	}
484→	callExpr := fmt.Sprintf("%s(%s)", funcName, strings.Join(argList, ", "))
485→
486→	if retInfo.Count == 0 {
487→		b.WriteString(fmt.Sprintf("\t%s\n", callExpr))
488→	} else if retInfo.Count == 1 {
489→		b.WriteString(fmt.Sprintf("\tresult := %s\n", callExpr))
490→	} else {
491→		// Multiple returns: capture into named vars
492→		retVars := make([]string, retInfo.Count)
493→		for i := range retInfo.Count {
494→			if i == retInfo.Count-1 && retInfo.HasErr {
495→				retVars[i] = "retErr"
496→			} else {
497→				retVars[i] = fmt.Sprintf("ret%d", i)
498→			}
499→		}
500→		b.WriteString(fmt.Sprintf("\t%s := %s\n", strings.Join(retVars, ", "), callExpr))
501→
502→		// If last return is error, check it
503→		if retInfo.HasErr {
504→			b.WriteString("\tif retErr != nil {\n")
505→			b.WriteString("\t\tfmt.Fprintf(os.Stderr, \"function returned error: %v\\n\", retErr)\n")
506→			b.WriteString("\t}\n")
507→		}
508→
509→		// Build a result struct for serialization
510→		if retInfo.Count == 1 || (retInfo.Count == 2 && retInfo.HasErr) {
511→			// Single meaningful return (possibly with error)
512→			b.WriteString(fmt.Sprintf("\tresult := ret0\n"))
513→		} else {
514→			// Multiple returns: wrap in a slice
515→			nonErrVars := retVars
516→			if retInfo.HasErr {
517→				nonErrVars = retVars[:len(retVars)-1]
518→			}
519→			ifaceVars := make([]string, len(nonErrVars))
520→			for i, v := range nonErrVars {
521→				ifaceVars[i] = fmt.Sprintf("any(%s)", v)
522→			}
523→			b.WriteString(fmt.Sprintf("\tresult := []any{%s}\n", strings.Join(ifaceVars, ", ")))
524→		}
525→	}
526→
527→	b.WriteString("\n")
528→
529→	// Dump shatter recording results
530→	resultsPathEscaped := strings.ReplaceAll(resultsPath, `\`, `\\`)
531→	b.WriteString(fmt.Sprintf("\tif err := __shatter_dump_results(%q); err != nil {\n", resultsPathEscaped))
532→	b.WriteString("\t\tfmt.Fprintf(os.Stderr, \"failed to dump results: %v\\n\", err)\n")
533→	b.WriteString("\t}\n")
534→
535→	// Write return value as JSON
536→	if retInfo.Count > 0 {
537→		returnPathEscaped := strings.ReplaceAll(returnPath, `\`, `\\`)
538→		b.WriteString(fmt.Sprintf("\n\treturnData, err := json.Marshal(result)\n"))
539→		b.WriteString("\tif err != nil {\n")
540→		b.WriteString("\t\tfmt.Fprintf(os.Stderr, \"failed to marshal return: %v\\n\", err)\n")
541→		b.WriteString("\t} else {\n")
542→		b.WriteString(fmt.Sprintf("\t\tos.WriteFile(%q, returnData, 0644)\n", returnPathEscaped))
543→		b.WriteString("\t}\n")
544→	}
545→
546→	// Write performance metrics
547→	perfPathEscaped := strings.ReplaceAll(perfPath, `\`, `\\`)
548→	b.WriteString("\n\tcpuElapsed := time.Since(cpuStart)\n")
549→	b.WriteString("\tvar memAfter runtime.MemStats\n")
550→	b.WriteString("\truntime.ReadMemStats(&memAfter)\n")
551→	b.WriteString("\tperfData, _ := json.Marshal(map[string]any{\n")
552→	b.WriteString("\t\t\"cpu_time_us\": cpuElapsed.Microseconds(),\n")
553→	b.WriteString("\t\t\"heap_used_bytes\": memAfter.HeapInuse - memBefore.HeapInuse,\n")
554→	b.WriteString("\t\t\"heap_allocated_bytes\": memAfter.TotalAlloc - memBefore.TotalAlloc,\n")
555→	b.WriteString("\t})\n")
556→	b.WriteString(fmt.Sprintf("\tos.WriteFile(%q, perfData, 0644)\n", perfPathEscaped))
557→
558→	b.WriteString("}\n")
559→
560→	return b.String(), nil
561→}
