147→func (h *Handler) handleHandshake(resp Response, req Request) Response {
148→	resp.Status = "handshake"
149→	resp.FrontendVersion = frontendVersion
150→	resp.Language = frontendLanguage
151→	caps := make([]string, len(CommandCapabilities))
152→	copy(caps, CommandCapabilities)
153→	caps = append(caps,
154→		"complex_type:date", "complex_type:duration", "complex_type:url",
155→		"complex_type:reg_exp", "complex_type:ip_address", "complex_type:big_int",
156→		"complex_type:rational", "complex_type:big_decimal", "complex_type:error",
157→	)
158→	resp.Capabilities = caps
159→	return resp
160→}
