210→func (h *Handler) handleInstrument(resp Response, req Request) Response {
211→	if req.File == "" {
212→		resp.Status = "error"
213→		resp.Code = ErrInvalidRequest
214→		resp.Message = "instrument command requires a file path"
215→		return resp
216→	}
217→
218→	if _, err := os.Stat(req.File); err != nil {
219→		resp.Status = "error"
220→		resp.Code = ErrFileNotFound
221→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
222→		return resp
223→	}
224→
225→	h.lastAnalyzedFile = req.File
226→
227→	outputDir, err := instrument.InstrumentFile(req.File, req.Function, req.ProjectRoot)
228→	if err != nil {
229→		resp.Status = "error"
230→		resp.Code = ErrInternalError
231→		resp.Message = fmt.Sprintf("instrumentation failed: %v", err)
232→		return resp
233→	}
234→
235→	instrumented := true
236→	resp.Status = "instrument"
237→	resp.Instrumented = &instrumented
238→	resp.OutputFile = &outputDir
239→	return resp
240→}
