335→func convertBranchPath(branches []instrument.BranchDecision) []BranchDecision {
336→	result := make([]BranchDecision, len(branches))
337→	for i, b := range branches {
338→		constraint := &SymConstraint{Kind: "unknown", Hint: "no symbolic constraint from Go frontend"}
339→		if b.ConstraintJSON != "" {
340→			var sc SymConstraint
341→			if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
342→				constraint = &sc
343→			}
344→		}
345→		result[i] = BranchDecision{
346→			BranchID:   b.BranchID,
347→			Line:       b.Line,
348→			Taken:      b.Taken,
349→			Constraint: constraint,
350→		}
351→	}
352→	return result
353→}
354→
355→func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
356→	var constraints []SymConstraint
357→	for _, b := range branches {
358→		if b.ConstraintJSON == "" {
359→			continue
360→		}
361→		var sc SymConstraint
362→		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
363→			constraints = append(constraints, sc)
364→		}
365→	}
366→	if constraints == nil {
367→		return []SymConstraint{}
368→	}
369→	return constraints
370→}
