372→// convertExternalCalls converts executor ExternalCall records to protocol format.
373→func convertExternalCalls(calls []instrument.ExternalCall) []ExternalCall {
374→	if len(calls) == 0 {
375→		return []ExternalCall{}
376→	}
377→	result := make([]ExternalCall, len(calls))
378→	for i, c := range calls {
379→		var args []any
380→		if c.Args != nil {
381→			json.Unmarshal(c.Args, &args) //nolint:errcheck
382→		}
383→		var retVal any
384→		if c.ReturnValue != nil {
385→			json.Unmarshal(c.ReturnValue, &retVal) //nolint:errcheck
386→		}
387→		result[i] = ExternalCall{
388→			Symbol:      c.Symbol,
389→			Args:        args,
390→			ReturnValue: retVal,
391→		}
392→	}
393→	return result
394→}
