396→// convertSideEffects converts executor SideEffects to protocol format.
397→func convertSideEffects(effects []instrument.SideEffect) []SideEffect {
398→	if len(effects) == 0 {
399→		return []SideEffect{}
400→	}
401→	result := make([]SideEffect, len(effects))
402→	for i, e := range effects {
403→		result[i] = SideEffect{
404→			Kind:    e.Kind,
405→			Level:   e.Level,
406→			Message: e.Message,
407→		}
408→	}
409→	return result
410→}
