412→func (h *Handler) handleSetup(resp Response, req Request) Response {
413→	if req.File == "" {
414→		resp.Status = "error"
415→		resp.Code = ErrInvalidRequest
416→		resp.Message = "setup command requires a file path"
417→		return resp
418→	}
419→	if req.Scope == "" {
420→		resp.Status = "error"
421→		resp.Code = ErrInvalidRequest
422→		resp.Message = "setup command requires a scope"
423→		return resp
424→	}
425→	if !req.Level.IsValid() {
426→		resp.Status = "error"
427→		resp.Code = ErrInvalidRequest
428→		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
429→		return resp
430→	}
431→
432→	if _, err := os.Stat(req.File); err != nil {
433→		resp.Status = "error"
434→		resp.Code = ErrFileNotFound
435→		resp.Message = fmt.Sprintf("setup file not found: %s", req.File)
436→		return resp
437→	}
438→
439→	var parentCtxJSON json.RawMessage
440→	if req.ParentContext != nil {
441→		data, err := json.Marshal(req.ParentContext)
442→		if err != nil {
443→			resp.Status = "error"
444→			resp.Code = ErrInternalError
445→			resp.Message = fmt.Sprintf("marshaling parent context: %v", err)
446→			return resp
447→		}
448→		parentCtxJSON = data
449→	}
450→
451→	h.log.Debug("Running setup", "file", req.File, "scope", req.Scope, "level", req.Level)
452→
453→	ctx, err := h.setupLoader.RunSetup(req.File, req.Scope, string(req.Level), req.ProjectRoot, parentCtxJSON)
454→	if err != nil {
455→		resp.Status = "error"
456→		resp.Code = ErrInternalError
457→		resp.Message = fmt.Sprintf("setup failed: %v", err)
458→		return resp
459→	}
460→
461→	resp.Status = "setup"
462→	ctxCopy := json.RawMessage(ctx)
463→	resp.SetupContext = &ctxCopy
464→	return resp
465→}
