  1→/**
  2→ * Function executor for the Shatter TypeScript frontend.
  3→ *
  4→ * Compiles TypeScript source to JavaScript, executes the target function
  5→ * with provided inputs in a sandboxed context, and returns the result
  6→ * with performance metrics and (for instrumented code) branch decisions.
  7→ */
  8→
  9→import * as ts from "typescript";
 10→import * as fs from "node:fs";
 11→import * as vm from "node:vm";
 12→import * as path from "node:path";
 13→import { createRequire } from "node:module";
 14→import { reconstructValue } from "./reconstruct.js";
 15→import type {
 16→  ExecuteResponse,
 17→  ErrorInfo,
 18→  ErrorCategory,
 19→  PerformanceMetrics,
 20→  BranchDecision,
 21→  SymConstraint,
 22→  SymExpr,
 23→  SideEffect,
 24→  TruncationInfo,
 25→  TraceEvent,
 26→  ScopeEvent,
 27→  DiscoveredDependency,
