153→/**
154→ * Transpile a TypeScript file to JavaScript and return the exports object.
155→ *
156→ * Results are cached by absolute file path.
157→ */
158→function loadModule(filePath: string): Record<string, unknown> {
159→  const absolutePath = path.resolve(filePath);
160→  const cached = compiledModuleCache.get(absolutePath);
161→  if (cached) return cached;
162→
163→  const source = fs.readFileSync(absolutePath, "utf-8");
164→  const result = ts.transpileModule(source, {
165→    compilerOptions: {
166→      target: ts.ScriptTarget.ES2022,
167→      module: ts.ModuleKind.CommonJS,
168→      esModuleInterop: true,
169→      strict: true,
170→      jsx: ts.JsxEmit.ReactJSX,
171→    },
172→    fileName: absolutePath,
173→  });
174→
175→  const targetRequire = wrapRequireWithReactShim(createRequire(absolutePath), absolutePath);
176→  const moduleExports: Record<string, unknown> = {};
177→  const moduleObj = { exports: moduleExports };
178→
179→  const sandbox = vm.createContext({
180→    module: moduleObj,
181→    exports: moduleExports,
182→    require: targetRequire,
183→    console: consoleProxy,
184→    process,
185→    Buffer,
186→    setTimeout,
187→    clearTimeout,
188→    setInterval,
189→    clearInterval,
190→    __filename: absolutePath,
191→    __dirname: path.dirname(absolutePath),
192→  });
193→
194→  vm.runInContext(result.outputText, sandbox, { filename: absolutePath, timeout: getExecTimeoutMs() });
195→
196→  // After CommonJS execution, module.exports may have been reassigned
197→  const finalExports = (sandbox as Record<string, unknown>)["module"] as { exports: Record<string, unknown> };
198→  const resolvedExports = finalExports.exports;
199→
200→  compiledModuleCache.set(absolutePath, resolvedExports);
201→  return resolvedExports;
202→}
203→
204→/**
205→ * Look up a function from the file path and function name.
206→ *
207→ * The function name may be a simple name like "classifyNumber" which is
208→ * looked up directly on the module exports. If it contains a colon
209→ * (file:function format from the analyze phase), the file portion is
210→ * stripped and only the function name is used.
211→ */
212→function resolveFunction(
213→  filePath: string,
214→  functionRef: string,
215→): (...args: unknown[]) => unknown {
216→  // Strip file prefix if present (e.g. "examples/foo.ts:myFunc" → "myFunc")
217→  const funcName = functionRef.includes(":")
218→    ? functionRef.split(":").pop()!
219→    : functionRef;
220→
221→  const moduleExports = loadModule(filePath);
222→  const fn = moduleExports[funcName];
223→
224→  if (typeof fn !== "function") {
225→    throw new Error(
226→      `Function "${funcName}" not found in exports of ${filePath}. ` +
227→      `Available exports: ${Object.keys(moduleExports).join(", ")}`,
228→    );
229→  }
230→
231→  return fn as (...args: unknown[]) => unknown;
232→}
233→
234→/**
235→ * Run garbage collection if --expose-gc is enabled.
236→ * This gives more accurate heap measurements by clearing unreachable objects.
237→ */
238→function tryGc(): void {
239→  if (typeof globalThis.gc === "function") {
240→    globalThis.gc();
241→  }
242→}
243→
244→/** Result of measuring a function execution. */
245→interface MeasuredExecution {
246→  returnValue: unknown;
247→  thrownError: ErrorInfo | null;
248→  performance: PerformanceMetrics;
249→}
250→
251→/**
252→ * Execute a callback with full performance instrumentation.
253→ *
254→ * Measures wall time via process.hrtime.bigint(), CPU time via process.cpuUsage(),
255→ * and heap delta via process.memoryUsage(). Optionally runs GC before measurement
256→ * if --expose-gc is enabled.
257→ */
258→async function measureExecution(fn: () => unknown): Promise<MeasuredExecution> {
259→  tryGc();
260→
261→  const startMem = process.memoryUsage();
262→  const startCpu = process.cpuUsage();
263→  const startTime = process.hrtime.bigint();
264→
265→  let returnValue: unknown = null;
266→  let thrownError: ErrorInfo | null = null;
267→
268→  try {
269→    const syncResult = fn();
270→    // If the function returned a Promise (async function), await it with timeout
271→    if (syncResult != null && typeof (syncResult as PromiseLike<unknown>).then === 'function') {
272→      const timeoutMs = getExecTimeoutMs();
273→      returnValue = await Promise.race([
274→        syncResult as Promise<unknown>,
275→        new Promise<never>((_, reject) =>
276→          setTimeout(() => reject(new Error("async execution timed out")), timeoutMs)
277→        ),
278→      ]);
279→    } else {
280→      returnValue = syncResult;
281→    }
282→  } catch (e: unknown) {
283→    const err = e as { constructor?: { name?: string }; message?: string; stack?: string };
284→    const errorType = err.constructor?.name ?? "Error";
285→    const errorMessage = String(err.message ?? e);
286→    thrownError = {
287→      error_type: errorType,
288→      message: errorMessage,
289→      stack: err.stack ?? null,
290→      error_category: classifyError(errorType, errorMessage),
291→    };
292→  }
293→
294→  const endTime = process.hrtime.bigint();
295→  const endCpu = process.cpuUsage(startCpu);
296→  const endMem = process.memoryUsage();
297→
298→  const wallTimeNs = endTime - startTime;
299→  const wallTimeMs = Number(wallTimeNs) / 1_000_000;
300→  const cpuTimeUs = endCpu.user + endCpu.system;
301→
302→  return {
303→    returnValue,
304→    thrownError,
305→    performance: {
306→      wall_time_ms: wallTimeMs,
307→      cpu_time_us: cpuTimeUs,
308→      heap_used_bytes: Math.max(0, endMem.heapUsed - startMem.heapUsed),
309→      heap_allocated_bytes: Math.max(0, endMem.heapTotal - startMem.heapTotal),
310→    },
311→  };
312→}
