573→/**
574→ * Execute instrumented TypeScript source code with branch-recording callbacks.
575→ *
576→ * The instrumented source must contain __shatter_record() and __shatter_branch()
577→ * calls inserted by the instrumentor. This function defines those callbacks,
578→ * executes the code, and collects the branch decisions.
579→ */
580→export async function executeInstrumented(
581→  instrumentedSource: string,
582→  functionName: string,
583→  inputs: unknown[],
584→  mocks: MockConfig[] = [],
585→  sourceFilePath?: string,
586→): Promise<RawExecuteResult> {
587→  // Transpile instrumented TS to JS
588→  const jsResult = ts.transpileModule(instrumentedSource, {
589→    compilerOptions: {
590→      target: ts.ScriptTarget.ES2022,
591→      module: ts.ModuleKind.CommonJS,
592→      esModuleInterop: true,
593→      strict: true,
594→      jsx: ts.JsxEmit.ReactJSX,
595→    },
596→    ...(sourceFilePath ? { fileName: sourceFilePath } : {}),
597→  });
598→
599→  const linesExecuted: number[] = [];
600→  const branchDecisions: BranchDecision[] = [];
601→  const sideEffects: SideEffect[] = [];
602→  const externalCalls: ExternalCall[] = [];
603→  const scopeEvents: TraceEvent[] = [];
604→  const discoveredDeps: DiscoveredDependency[] = [];
605→  const seenDiscoveredModules = new Set<string>();
606→
607→  // Define the runtime callbacks
608→  const recordFn = (line: number): void => {
609→    linesExecuted.push(line);
610→  };
611→
612→  const branchFn = (
613→    branchId: number,
614→    line: number,
615→    conditionResult: boolean,
616→    symExpr: SymExpr,
617→  ): boolean => {
618→    const constraint: SymConstraint = symExpr.kind !== "unknown"
619→      ? { kind: "expr", expr: symExpr }
620→      : { kind: "unknown", hint: "unsupported expression" };
621→
622→    const decision: BranchDecision = {
623→      branch_id: branchId,
624→      line,
625→      taken: conditionResult,
626→      constraint,
627→    };
628→    branchDecisions.push(decision);
629→    scopeEvents.push({ type: "branch", decision });
630→
631→    return conditionResult;
632→  };
633→
634→  const scopeEventFn = (scopeId: number, kind: string): void => {
635→    const event: ScopeEvent = kind.startsWith("loop")
636→      ? { kind: kind as "loop_enter" | "loop_exit", loop_id: scopeId }
637→      : { kind: kind as "call_enter" | "call_exit", call_site_id: scopeId };
638→    scopeEvents.push({ type: "scope", event });
639→  };
640→
641→  // Build mock registry from MockConfig array
642→  const mockRegistry: Record<string, (...args: unknown[]) => unknown> = {};
643→  for (const mock of mocks) {
644→    if (mock.default_behavior === "passthrough") {
645→      continue;
646→    }
647→    if (mock.default_behavior === "throw_error") {
648→      let callIndex = 0;
649→      const returnValues = mock.return_values;
650→      mockRegistry[mock.symbol] = (): never => {
651→        // Use return_values as error details if available
652→        if (returnValues.length > 0) {
653→          const idx = Math.min(callIndex, returnValues.length - 1);
654→          callIndex++;
655→          const errData = returnValues[idx];
656→          const message = typeof errData === "object" && errData !== null && "message" in errData
657→            ? String((errData as Record<string, unknown>)["message"])
658→            : `Mock error: ${mock.symbol}`;
659→          throw new Error(message);
660→        }
661→        throw new Error(`Mock error: ${mock.symbol}`);
662→      };
663→      continue;
664→    }
665→    let callIndex = 0;
666→    const returnValues = mock.return_values;
667→    mockRegistry[mock.symbol] = (...args: unknown[]): unknown => {
668→      if (returnValues.length > 0) {
669→        const idx = mock.default_behavior === "repeat_last"
670→          ? Math.min(callIndex, returnValues.length - 1)
671→          : callIndex % returnValues.length;
672→        callIndex++;
673→        return returnValues[idx];
674→      }
675→      return undefined;
676→    };
677→  }
678→
679→  // Mock call recorder
680→  const mockCallFn = (
681→    moduleName: string,
682→    symbolName: string,
683→    args: unknown[],
684→    returnValue: unknown,
685→  ): void => {
686→    externalCalls.push({
687→      symbol: `${moduleName}:${symbolName}`,
688→      args: Array.isArray(args) ? args : [],
689→      return_value: returnValue,
690→    });
691→  };
692→
693→  // Build the execution context with capturing console and process
694→  const capturingConsole = createCapturingConsole(sideEffects);
695→  const capturingProc = createCapturingProcess(sideEffects);
696→  const rawRequire = sourceFilePath ? createRequire(path.resolve(sourceFilePath)) : require;
697→  const baseRequire = wrapRequireWithReactShim(rawRequire, sourceFilePath);
698→
699→  // Collect mocked module prefixes for gap detection
700→  const mockedModulePrefixes = new Set<string>();
701→  for (const key of Object.keys(mockRegistry)) {
702→    const colonIdx = key.indexOf(":");
703→    if (colonIdx > 0) {
704→      mockedModulePrefixes.add(key.substring(0, colonIdx));
705→    }
706→  }
707→
708→  // Wrap require to detect unmocked external imports and subprocess APIs
709→  const sandboxRequire = (id: string): unknown => {
710→    const result = baseRequire(id);
711→
712→    // Skip relative/absolute paths (local modules) and already-seen modules
713→    if (!id.startsWith(".") && !id.startsWith("/") && !seenDiscoveredModules.has(id)) {
714→      seenDiscoveredModules.add(id);
715→
716→      const isSubprocessModule = SUBPROCESS_MODULES.has(id);
717→      const isMocked = mockedModulePrefixes.has(id);
718→
719→      if (isSubprocessModule) {
720→        discoveredDeps.push({
721→          symbol: id,
722→          source_module: id,
723→          kind: "subprocess_spawn",
724→          is_subprocess_spawn: true,
725→        });
726→      } else if (!isMocked) {
727→        discoveredDeps.push({
728→          symbol: id,
729→          source_module: id,
730→          kind: "unmocked_import",
731→          is_subprocess_spawn: false,
732→        });
733→      }
734→    }
735→
736→    return result;
737→  };
738→  const moduleExports: Record<string, unknown> = {};
739→  const moduleObj = { exports: moduleExports };
740→
741→  const sandbox = vm.createContext({
742→    module: moduleObj,
743→    exports: moduleExports,
744→    require: sandboxRequire,
745→    console: capturingConsole,
746→    process: capturingProc,
747→    Buffer,
748→    setTimeout,
749→    clearTimeout,
750→    setInterval,
751→    clearInterval,
752→    ...(sourceFilePath ? { __filename: sourceFilePath, __dirname: path.dirname(sourceFilePath) } : {}),
753→    [RECORD_FUNCTION]: recordFn,
754→    [BRANCH_FUNCTION]: branchFn,
755→    [SCOPE_EVENT_FUNCTION]: scopeEventFn,
756→    [MOCK_REGISTRY]: mockRegistry,
757→    [MOCK_CALL_FUNCTION]: mockCallFn,
758→  });
759→
760→  vm.runInContext(jsResult.outputText, sandbox, { filename: sourceFilePath ?? "instrumented.js", timeout: getExecTimeoutMs() });
761→
762→  // Resolve the function from the module exports
763→  const finalExports = (sandbox as Record<string, unknown>)["module"] as { exports: Record<string, unknown> };
764→
765→  // Snapshot module-level variables before execution
766→  const exportKeys = Object.keys(finalExports.exports).filter(
767→    (k) => typeof finalExports.exports[k] !== "function",
768→  );
769→  const beforeSnapshot = new Map<string, unknown>();
770→  for (const key of exportKeys) {
771→    beforeSnapshot.set(key, structuredClone(finalExports.exports[key]));
772→  }
773→
774→  const fn = finalExports.exports[functionName];
775→
776→  if (typeof fn !== "function") {
777→    throw new Error(
778→      `Function "${functionName}" not found in instrumented module exports. ` +
779→      `Available: ${Object.keys(finalExports.exports).join(", ")}`,
780→    );
781→  }
782→
783→  const reconstructedInputs = inputs.map(reconstructValue);
784→  const metrics = await measureExecution(
785→    () => (fn as (...args: unknown[]) => unknown)(...reconstructedInputs),
786→  );
787→
788→  if (metrics.thrownError) {
789→    sideEffects.push({
790→      kind: "thrown_error",
791→      error_type: metrics.thrownError.error_type,
792→      message: metrics.thrownError.message,
793→      stack: metrics.thrownError.stack,
794→    });
795→  }
796→
797→  // Detect module-level variable changes after execution
798→  for (const key of exportKeys) {
799→    const before = beforeSnapshot.get(key);
800→    const after = finalExports.exports[key];
801→    if (JSON.stringify(before) !== JSON.stringify(after)) {
802→      sideEffects.push({
803→        kind: "global_state_change",
804→        variable: key,
805→        before,
806→        after,
807→      });
808→    }
809→  }
810→
811→  // Build path_constraints: the conjunction of constraints along the taken path
812→  const pathConstraints = branchDecisions.map((bd) => bd.constraint);
813→
814→  return {
815→    return_value: metrics.returnValue ?? null,
816→    thrown_error: metrics.thrownError,
817→    side_effects: sideEffects,
818→    branch_path: branchDecisions,
819→    path_constraints: pathConstraints,
820→    lines_executed: linesExecuted,
821→    performance: metrics.performance,
822→    calls_to_external: externalCalls,
823→    scope_events: scopeEvents,
824→    discovered_dependencies: discoveredDeps,
825→  };
826→}
